#include <stdio.h>
int main() {
    int T, N, Ai, totalCandies, sammyCandies, simmyCandies;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        totalCandies = 0;
        for (int i = 0; i < N; i++) {
            scanf("%d", &Ai);
            totalCandies += Ai;
        }
        if (totalCandies % 2 == 0) {
            sammyCandies = totalCandies / 2 + 1;
            simmyCandies = totalCandies / 2;
        } else {
            sammyCandies = totalCandies / 2 + 1;
            simmyCandies = totalCandies / 2;
        }
        if (sammyCandies > simmyCandies && sammyCandies - simmyCandies <= 1) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

